SELECT
gl.location_name AS locationName,
pr.price
FROM price_record pr
INNER JOIN geo_location gl ON pr.location_id = gl.id
INNER JOIN price_source ps ON pr.source_id = ps.id
WHERE 1=1


    AND pr.item_id = #{dto.itemId}


    AND pr.item_id = (SELECT id FROM price_item WHERE item_code = #{dto.itemCode} LIMIT 1)



    AND pr.location_id IN

        #{locId}




    AND pr.source_id IN

        #{sid}




    AND ps.reliability_level >= #{dto.minReliability}



    AND pr.currency = #{dto.currency}



    AND pr.confidence >= #{dto.minConfidence}


AND pr.effective_time <= #{dto.targetTime}
ORDER BY pr.effective_time DESC

SELECT
ps.source_name AS sourceName,
pr.price,
ps.reliability_level AS reliabilityLevel,
pr.confidence
FROM price_record pr
INNER JOIN price_source ps ON pr.source_id = ps.id
INNER JOIN price_item pi ON pr.item_id = pi.id
WHERE 1=1


    AND pr.item_id = #{dto.itemId}


    AND pr.item_id = (SELECT id FROM price_item WHERE item_code = #{dto.itemCode} LIMIT 1)



    AND pr.item_id IN

        #{id}




    AND pr.source_id IN

        #{sid}




    AND ps.reliability_level >= #{dto.minReliability}



    AND pr.currency = #{dto.currency}



    AND pr.confidence >= #{dto.minConfidence}


AND pr.effective_time <= #{dto.targetTime}
ORDER BY pr.effective_time DESC
